package com.wjx871.population.cancellation;import com.wjx871.population.application.*;import lombok.RequiredArgsConstructor;import org.springframework.stereotype.Component;
@Component @RequiredArgsConstructor public class CancellationStatusListener implements ApplicationStatusListener {private final CancellationMapper mapper;public boolean supports(BusinessType t){return t==BusinessType.PERSON_CANCELLATION||t==BusinessType.HOUSEHOLD_CANCELLATION;}public void onStatusChanged(BusinessApplication a,ApplicationStatus s){CancellationRecord r=mapper.findByApplication(a.getApplicationId()).orElse(null);if(r==null)return;if(mapper.updateStatus(a.getApplicationId(),r.getBusinessStatus(),CancellationStatus.valueOf(s.name()),r.getVersion(),null)==0)ApplicationService.conflict();}}
